begin;
alter table public.recommendation_history drop constraint if exists recommendation_history_action_check;
alter table public.recommendation_history add constraint recommendation_history_action_check check(action in('generated','accepted','dismissed','snoozed','completed','reviewed','never_remind','view','create_task','create_calendar_event','convert_maintenance','helpful','not_helpful','too_early','too_late','already_done','expired','ignored'));
create table if not exists public.recommendation_feedback(id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households(id) on delete cascade,user_id uuid not null default auth.uid() references auth.users(id) on delete cascade,recommendation_key text not null,feedback_type text not null check(feedback_type in('helpful','not_helpful','too_early','too_late','already_done','dont_show_again')),context jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table if not exists public.recommendation_effectiveness(id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households(id) on delete cascade,user_id uuid not null default auth.uid() references auth.users(id) on delete cascade,recommendation_key text not null,state text not null check(state in('shown','viewed','completed','dismissed','snoozed','ignored','expired','never_remind')),occurred_at timestamptz not null default now(),metadata jsonb not null default '{}'::jsonb);
create table if not exists public.recommendation_learning(id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households(id) on delete cascade,user_id uuid not null default auth.uid() references auth.users(id) on delete cascade,pattern_key text not null,pattern_type text not null,observation_count integer not null default 0,confidence numeric(5,2) not null default 0 check(confidence between 0 and 100),explanation text not null default '',learned_value jsonb not null default '{}'::jsonb,updated_at timestamptz not null default now(),unique(household_id,user_id,pattern_key));
create table if not exists public.recommendation_dependencies(id uuid primary key default gen_random_uuid(),household_id uuid not null references public.households(id) on delete cascade,recommendation_key text not null,depends_on_key text not null,relationship_type text not null check(relationship_type in('blocks','depends_on','related','duplicate','prerequisite')),created_by uuid not null default auth.uid() references auth.users(id) on delete cascade,created_at timestamptz not null default now(),unique(household_id,recommendation_key,depends_on_key,relationship_type));
create index if not exists recommendation_effectiveness_metrics_idx on public.recommendation_effectiveness(household_id,user_id,state,occurred_at desc);
create index if not exists recommendation_feedback_key_idx on public.recommendation_feedback(household_id,user_id,recommendation_key,created_at desc);
do $$ declare t text;begin foreach t in array array['recommendation_feedback','recommendation_effectiveness','recommendation_learning','recommendation_dependencies'] loop execute format('alter table public.%I enable row level security',t);execute format('revoke all on public.%I from anon,public',t);execute format('grant select,insert,update,delete on public.%I to authenticated',t);execute format('drop policy if exists %I on public.%I',t||'_household_access',t);if t='recommendation_dependencies' then execute format('create policy %I on public.%I for all to authenticated using(public.familyos_is_household_member(household_id)) with check(created_by=auth.uid() and public.familyos_has_household_role(household_id,array[''owner'',''adult'']))',t||'_household_access',t);else execute format('create policy %I on public.%I for all to authenticated using(user_id=auth.uid() and public.familyos_is_household_member(household_id)) with check(user_id=auth.uid() and public.familyos_has_household_role(household_id,array[''owner'',''adult'']))',t||'_household_access',t);end if;end loop;end $$;
commit;
